import Foundation

// MARK: - Protocol (injectable for tests)

/// Delivers file content whenever the watched file changes.
public protocol FileWatching: Sendable {
    /// An async sequence of file `Data` snapshots, emitted on each detected change.
    func changes() -> AsyncStream<Data>
}

// MARK: - Production implementation

/// Watches a single file using FS events (DispatchSource) with a polling fallback.
///
/// Hybrid strategy: a `DispatchSource.makeFileSystemObjectSource` watches for
/// `.write` events. A fallback timer re-checks every `pollInterval` seconds in
/// case FS events are missed (network mounts, fd invalidation after atomic
/// replace). Events are debounced so rapid successive writes produce one read.
public final class UsagesFileWatcher: FileWatching, @unchecked Sendable {
    private let path: String
    private let pollInterval: TimeInterval
    private let debounceInterval: TimeInterval
    private let logger: FileLogger

    public static let defaultPollSeconds: TimeInterval = 30
    public static let defaultDebounceSeconds: TimeInterval = 0.5

    public init(
        path: String,
        pollInterval: TimeInterval = UsagesFileWatcher.defaultPollSeconds,
        debounceInterval: TimeInterval = UsagesFileWatcher.defaultDebounceSeconds,
        logger: FileLogger = Loggers.app
    ) {
        self.path = path
        self.pollInterval = pollInterval
        self.debounceInterval = debounceInterval
        self.logger = logger
    }

    public func changes() -> AsyncStream<Data> {
        let path = self.path
        let pollInterval = self.pollInterval
        let logger = self.logger

        return AsyncStream { continuation in
            let watcherTask = Task {
                var lastModDate: Date?
                var dispatchSource: DispatchSourceFileSystemObject?
                var fileDescriptor: Int32 = -1

                // Signal that the file changed; actual read + dedup happens here
                func emitIfChanged() {
                    guard let attrs = try? FileManager.default.attributesOfItem(atPath: path),
                          let modDate = attrs[.modificationDate] as? Date else {
                        return
                    }
                    if modDate != lastModDate {
                        lastModDate = modDate
                        if let data = FileManager.default.contents(atPath: path) {
                            continuation.yield(data)
                        }
                    }
                }

                func openSource() -> (DispatchSourceFileSystemObject, Int32)? {
                    let fd = open(path, O_EVTONLY)
                    guard fd >= 0 else { return nil }
                    let source = DispatchSource.makeFileSystemObjectSource(
                        fileDescriptor: fd,
                        eventMask: [.write, .delete, .rename],
                        queue: DispatchQueue.global(qos: .utility)
                    )
                    source.setEventHandler { emitIfChanged() }
                    source.setCancelHandler { close(fd) }
                    source.resume()
                    return (source, fd)
                }

                // Initial read if file already exists
                emitIfChanged()

                if let (src, fd) = openSource() {
                    dispatchSource = src
                    fileDescriptor = fd
                    logger.log(.debug, "FileWatcher: FS events active on \(path)")
                }

                // Polling fallback — also re-opens FS source when file is recreated
                while !Task.isCancelled {
                    try? await Task.sleep(nanoseconds: UInt64(pollInterval * 1_000_000_000))
                    guard !Task.isCancelled else { break }

                    emitIfChanged()

                    // Re-establish FS watcher if fd went stale (file was replaced)
                    let fileExists = FileManager.default.fileExists(atPath: path)
                    let fdValid = fileDescriptor >= 0 && fcntl(fileDescriptor, F_GETFD) != -1
                    if fileExists && !fdValid {
                        dispatchSource?.cancel()
                        if let (src, fd) = openSource() {
                            dispatchSource = src
                            fileDescriptor = fd
                            logger.log(.debug, "FileWatcher: re-opened FS source on \(path)")
                        }
                    }
                }

                dispatchSource?.cancel()
                continuation.finish()
            }

            continuation.onTermination = { _ in watcherTask.cancel() }
        }
    }
}

import Foundation
import Observation

// MARK: - Clock abstraction (testable time source)

/// Abstracts `Date.now` so tests can inject a fixed point in time.
public protocol ClockProvider: Sendable {
    func now() -> Date
}

/// Default clock that returns the real current date.
public struct SystemClock: ClockProvider {
    public init() {}
    public func now() -> Date { Date() }
}

// MARK: - Store

/// Observable view-model that decodes `usages.json`, extracts the active
/// Claude account's time-window metrics, and formats them for the menu bar.
///
/// Format: `S 48% 2h13m | W 7% 6d 6h 13m`
/// Fallback: `"--"` when data is unavailable or malformed.
@Observable
@MainActor
public final class UsageStore {
    // MARK: Published state

    public private(set) var menuBarText: String = "--"

    // MARK: Dependencies

    private let fileWatcher: FileWatching
    private let clock: ClockProvider
    private let logger: FileLogger
    private let countdownRefreshSeconds: UInt64

    public static let defaultCountdownRefreshSeconds: UInt64 = 60
    private static let fallbackText = "--"
    private static let targetVendor = "claude"

    // Latest decoded file kept for countdown refresh without re-reading disk
    private var lastFile: UsagesFile?

    // MARK: Tasks

    private var watchTask: Task<Void, Never>?
    private var countdownTask: Task<Void, Never>?

    // MARK: Init

    public init(
        fileWatcher: FileWatching,
        clock: ClockProvider = SystemClock(),
        logger: FileLogger = Loggers.app,
        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
    ) {
        self.fileWatcher = fileWatcher
        self.clock = clock
        self.logger = logger
        self.countdownRefreshSeconds = countdownRefreshSeconds
    }

    // MARK: Lifecycle

    /// Start watching the file and refreshing the countdown.
    /// Idempotent — calling again is a no-op.
    public func start() {
        guard watchTask == nil else { return }

        let watcher = fileWatcher
        watchTask = Task { [weak self] in
            for await data in watcher.changes() {
                guard let self, !Task.isCancelled else { break }
                self.handleNewData(data)
            }
        }

        countdownTask = Task { [weak self] in
            guard let self else { return }
            let refreshNanos = self.countdownRefreshSeconds * 1_000_000_000
            while !Task.isCancelled {
                try? await Task.sleep(nanoseconds: refreshNanos)
                guard !Task.isCancelled else { break }
                self.refreshMenuBarText()
            }
        }
    }

    /// Stop all background tasks. Idempotent.
    public func stop() {
        watchTask?.cancel()
        watchTask = nil
        countdownTask?.cancel()
        countdownTask = nil
    }

    // MARK: - Processing

    private func handleNewData(_ data: Data) {
        do {
            let file = try JSONDecoder().decode(UsagesFile.self, from: data)
            lastFile = file
            menuBarText = format(file: file)
        } catch {
            logger.log(.error, "UsageStore: JSON decode failed: \(error)")
            lastFile = nil
            menuBarText = Self.fallbackText
        }
    }

    private func refreshMenuBarText() {
        guard let file = lastFile else { return }
        menuBarText = format(file: file)
    }

    // MARK: - Formatting

    private func format(file: UsagesFile) -> String {
        guard let entry = file.usages.first(where: {
            $0.vendor == Self.targetVendor && $0.isActive
        }) else {
            return Self.fallbackText
        }

        let segments = entry.metrics.compactMap { metric -> String? in
            formatTimeWindowSegment(metric)
        }

        return segments.isEmpty ? Self.fallbackText : segments.joined(separator: " | ")
    }

    private func formatTimeWindowSegment(_ metric: UsageMetric) -> String? {
        guard case let .timeWindow(name, resetAt, _, usagePercent) = metric else {
            return nil
        }

        let abbreviation = name.prefix(1).uppercased()
        let remaining = formatRemainingTime(resetAt: resetAt)
        return "\(abbreviation) \(usagePercent)% \(remaining)"
    }

    private func formatRemainingTime(resetAt isoString: String) -> String {
        let formatter = ISO8601DateFormatter()
        guard let resetDate = formatter.date(from: isoString) else {
            return "0m"
        }

        let now = clock.now()
        let totalSeconds = Int(resetDate.timeIntervalSince(now))

        guard totalSeconds > 0 else { return "0m" }

        let secondsPerMinute = 60
        let secondsPerHour = 3600
        let secondsPerDay = 86400

        let days = totalSeconds / secondsPerDay
        let hours = (totalSeconds % secondsPerDay) / secondsPerHour
        let minutes = (totalSeconds % secondsPerHour) / secondsPerMinute

        var parts: [String] = []
        if days > 0 { parts.append("\(days)d") }
        if hours > 0 { parts.append("\(hours)h") }
        // Always show minutes unless we have days+hours already
        if minutes > 0 || parts.isEmpty { parts.append("\(minutes)m") }

        return parts.joined(separator: " ")
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Test doubles

/// A mock FileWatching that lets tests push arbitrary Data payloads.
struct MockFileWatcher: FileWatching {
    let stream: AsyncStream<Data>
    let continuation: AsyncStream<Data>.Continuation

    init() {
        var cont: AsyncStream<Data>.Continuation!
        stream = AsyncStream { cont = $0 }
        continuation = cont
    }

    func changes() -> AsyncStream<Data> { stream }

    func send(_ data: Data) { continuation.yield(data) }
    func finish() { continuation.finish() }
}

/// A clock fixed at a given date, for deterministic remaining-time formatting.
struct FixedClock: ClockProvider {
    let date: Date
    init(_ date: Date) { self.date = date }
    func now() -> Date { date }
}

// MARK: - Helpers

/// Builds valid JSON `Data` for a `UsagesFile`.
private func makeUsagesJSON(
    vendor: String = "claude",
    account: String = "user@example.com",
    isActive: Bool = true,
    metrics: [[String: Any]] = []
) -> Data {
    let entry: [String: Any] = [
        "vendor": vendor,
        "account": account,
        "isActive": isActive,
        "metrics": metrics,
    ]
    let root: [String: Any] = ["usages": [entry]]
    return try! JSONSerialization.data(withJSONObject: root)
}

private func timeWindowMetric(
    name: String = "session",
    resetAt: String = "2026-04-17T15:00:00Z",
    windowDurationMinutes: Int = 300,
    usagePercent: Int = 42
) -> [String: Any] {
    [
        "type": "time-window",
        "name": name,
        "resetAt": resetAt,
        "windowDurationMinutes": windowDurationMinutes,
        "usagePercent": usagePercent,
    ]
}

private func payAsYouGoMetric(
    name: String = "monthly",
    currentAmount: Double = 12.50,
    currency: String = "USD"
) -> [String: Any] {
    [
        "type": "pay-as-you-go",
        "name": name,
        "currentAmount": currentAmount,
        "currency": currency,
    ]
}

// MARK: - Tests

@Suite("UsageStore formatting")
struct UsageStoreFormattingTests {

    // Fixed reference time: 2026-04-17T12:47:00Z
    private var referenceDate: Date {
        let f = ISO8601DateFormatter()
        return f.date(from: "2026-04-17T12:47:00Z")!
    }

    @MainActor
    @Test("default menuBarText is fallback")
    func defaultIsFallback() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher)
        #expect(store.menuBarText == "--")
    }

    @MainActor
    @Test("single time-window metric formats correctly")
    func singleTimeWindow() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        // resetAt is 2h13m in the future from referenceDate
        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
        ])
        watcher.send(data)

        // Let the async stream deliver
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 48% 2h 13m")
        store.stop()
    }

    @MainActor
    @Test("multiple time-window metrics joined by pipe")
    func multipleTimeWindows() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
            timeWindowMetric(name: "weekly", resetAt: "2026-04-23T21:00:00Z", usagePercent: 7),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 48% 2h 13m | W 7% 6d 8h 13m")
        store.stop()
    }

    @MainActor
    @Test("pay-as-you-go metrics are ignored")
    func payAsYouGoIgnored() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            payAsYouGoMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        // No time-window metrics → fallback
        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("mixed metrics: only time-window rendered")
    func mixedMetrics() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
            payAsYouGoMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 48% 2h 13m")
        store.stop()
    }

    @MainActor
    @Test("resetAt in the past shows 0m")
    func resetAtInPast() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T10:00:00Z", usagePercent: 100),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 100% 0m")
        store.stop()
    }

    @MainActor
    @Test("resetAt exactly now shows 0m")
    func resetAtExactlyNow() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T12:47:00Z", usagePercent: 50),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 50% 0m")
        store.stop()
    }
}

@Suite("UsageStore graceful degradation")
struct UsageStoreDegradationTests {

    @MainActor
    @Test("malformed JSON falls back to --")
    func malformedJSON() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        watcher.send("not json".data(using: .utf8)!)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("no active Claude entry falls back to --")
    func noActiveClaude() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(isActive: false, metrics: [
            timeWindowMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("wrong vendor falls back to --")
    func wrongVendor() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(vendor: "other", metrics: [
            timeWindowMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("active Claude entry with empty metrics falls back to --")
    func emptyMetrics() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("subsequent valid data recovers from error state")
    func recoveryAfterError() async throws {
        let watcher = MockFileWatcher()
        let f = ISO8601DateFormatter()
        let clock = FixedClock(f.date(from: "2026-04-17T12:00:00Z")!)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        // Bad data first
        watcher.send("bad".data(using: .utf8)!)
        try await Task.sleep(nanoseconds: 50_000_000)
        #expect(store.menuBarText == "--")

        // Then valid data
        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T13:00:00Z", usagePercent: 10),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)
        #expect(store.menuBarText == "S 10% 1h")

        store.stop()
    }
}

@Suite("UsageStore lifecycle")
struct UsageStoreLifecycleTests {

    @MainActor
    @Test("start is idempotent")
    func startIdempotent() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()
        store.start() // second call should be no-op
        store.stop()
    }

    @MainActor
    @Test("stop is idempotent")
    func stopIdempotent() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()
        store.stop()
        store.stop() // second call should be no-op
    }

    @MainActor
    @Test("stop before start is safe")
    func stopBeforeStart() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.stop()
    }
}

